#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        char s[200005]; scanf("%s",s);
        int best[26][2]; memset(best,0,sizeof(best));
        int curLen=0; char curChar=0;
        for(int i=0;i<N;i++){
            if(i==0 || s[i]!=s[i-1]){
                if(i!=0){
                    int idx=curChar-'a';
                    if(curLen>best[idx][0]){best[idx][1]=best[idx][0];best[idx][0]=curLen;}
                    else if(curLen>best[idx][1]) best[idx][1]=curLen;
                }
                curChar=s[i]; curLen=1;
            }else curLen++;
        }
        // last run
        int idx=curChar-'a';
        if(curLen>best[idx][0]){best[idx][1]=best[idx][0];best[idx][0]=curLen;}
        else if(curLen>best[idx][1]) best[idx][1]=curLen;
        int ans=0;
        for(int c=0;c<26;c++){
            int L1=best[c][0];
            int L2=best[c][1];
            int cand = L1>0 ? (L1-1> L2 ? L1-1 : L2) : 0;
            if(cand>ans) ans=cand;
        }
        printf("%d\n",ans);
    }
    return 0;
}

