    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            String s = br.readLine().trim();
            int[][] best = new int[26][2];
            int curLen = 0; char curChar = 0;
            for (int i = 0; i < N; i++) {
                char ch = s.charAt(i);
                if (i == 0 || ch != s.charAt(i - 1)) {
                    if (i != 0) {
                        int idx = curChar - 'a';
                        if (curLen > best[idx][0]) { best[idx][1] = best[idx][0]; best[idx][0] = curLen; }
                        else if (curLen > best[idx][1]) best[idx][1] = curLen;
                    }
                    curChar = ch; curLen = 1;
                } else {
                    curLen++;
                }
            }
            int idx = curChar - 'a';
            if (curLen > best[idx][0]) { best[idx][1] = best[idx][0]; best[idx][0] = curLen; }
            else if (curLen > best[idx][1]) best[idx][1] = curLen;
            int ans = 0;
            for (int c = 0; c < 26; c++) {
                int L1 = best[c][0];
                int L2 = best[c][1];
