import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        best = [[0,0] for _ in range(26)]
        cur_len = 0
        cur_char = ''
        for i,ch in enumerate(s):
            if i==0 or ch!=s[i-1]:
                if i!=0:
                    idx = ord(cur_char)-97
                    if cur_len>best[idx][0]:
                        best[idx][1]=best[idx][0]
                        best[idx][0]=cur_len
                    elif cur_len>best[idx][1]:
                        best[idx][1]=cur_len
                cur_char = ch
                cur_len = 1
            else:
                cur_len+=1
        idx = ord(cur_char)-97
        if cur_len>best[idx][0]:
            best[idx][1]=best[idx][0]
            best[idx][0]=cur_len
        elif cur_len>best[idx][1]:
            best[idx][1]=cur_len
        ans = 0
        for L1,L2 in best:
            cand = max(L1-1 if L1>0 else 0, L2)
            if cand>ans:
                ans=cand
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

